void md(
    const POSVECTYPE* __restrict__ d_position,
    FORCEVECTYPE* __restrict__ d_force,
    const int* __restrict__ d_neighborList,
    const int nAtom,
    const int maxNeighbors_,
    const FPTYPE lj1_t,
    const FPTYPE lj2_t,
    const FPTYPE cutsq_t)
{
  const int threads = 256;
  const int blocks = (nAtom + threads - 1) / threads;
  md_kernel<<<blocks, threads>>>(d_position, d_force, d_neighborList, nAtom,
                                 maxNeighbors_, lj1_t, lj2_t, cutsq_t);
  CUDA_CHECK(cudaGetLastError());
  CUDA_CHECK(cudaDeviceSynchronize());
}

int main(int argc, char** argv)
{
  if (argc != 3) {
    printf("usage: %s <class size> <iteration>", argv[0]);
    return 1;
  }

  int sizeClass = atoi(argv[1]);
  int iteration = atoi(argv[2]);
  const int probSizes[] = { 12288, 24576, 36864, 73728 };
  assert(sizeClass >= 0 && sizeClass < 4);
  assert(iteration >= 0);

  int nAtom = probSizes[sizeClass];

  POSVECTYPE* position = (POSVECTYPE*) malloc(nAtom * sizeof(POSVECTYPE));
  FORCEVECTYPE* force = (FORCEVECTYPE*) malloc(nAtom * sizeof(FORCEVECTYPE));
  int *neighborList = (int*) malloc(maxNeighbors * nAtom * sizeof(int));

  std::cout << "Initializing test problem (this can take several minutes for large problems).\n";

  srand(123);

  for (int i = 0; i < nAtom; i++)
  {
    position[i].x = rand() % domainEdge;
    position[i].y = rand() % domainEdge;
    position[i].z = rand() % domainEdge;
    position[i].w = 0;
  }

  std::cout << "Finished.\n";
  int totalPairs = buildNeighborList<FPTYPE, POSVECTYPE>(nAtom, position, neighborList);
  std::cout << totalPairs << " of " << nAtom*maxNeighbors
            << " pairs within cutoff distance = "
            << 100.0 * ((double)totalPairs / (nAtom*maxNeighbors)) << " %\n";

  POSVECTYPE* d_position = nullptr;
  FORCEVECTYPE* d_force = nullptr;
  int* d_neighborList = nullptr;

  CUDA_CHECK(cudaMalloc((void**)&d_position, nAtom * sizeof(POSVECTYPE)));
  CUDA_CHECK(cudaMalloc((void**)&d_force, nAtom * sizeof(FORCEVECTYPE)));
  CUDA_CHECK(cudaMalloc((void**)&d_neighborList, maxNeighbors * nAtom * sizeof(int)));

  CUDA_CHECK(cudaMemcpy(d_position, position, nAtom * sizeof(POSVECTYPE), cudaMemcpyHostToDevice));
  CUDA_CHECK(cudaMemcpy(d_neighborList, neighborList, maxNeighbors * nAtom * sizeof(int), cudaMemcpyHostToDevice));

  md(d_position,
     d_force,
     d_neighborList,
     nAtom,
     maxNeighbors,
     lj1,
     lj2,
     cutsq);

  CUDA_CHECK(cudaMemcpy(force, d_force, nAtom * sizeof(FORCEVECTYPE), cudaMemcpyDeviceToHost));

  std::cout << "Performing Correctness Check (may take several minutes)\n";

  checkResults<FPTYPE, FORCEVECTYPE, POSVECTYPE>(force, position, neighborList, nAtom);

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < iteration; i++) {
    md(d_position,
       d_force,
       d_neighborList,
       nAtom,
       maxNeighbors,
       lj1,
       lj2,
       cutsq);
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average kernel execution time " << (time * 1e-9f) / iteration << " (s)\n";

  CUDA_CHECK(cudaFree(d_position));
  CUDA_CHECK(cudaFree(d_force));
  CUDA_CHECK(cudaFree(d_neighborList));

  free(position);
  free(force);
  free(neighborList);

  return 0;
}
